type WarnOptions = {
    /**
     * Show warning only once.
     *
     * @default true
     */
    once?: boolean;
    /**
     * Name of the module throwing the warning, as installed in node_modules.
     * This is used to filter the stack trace to show only the relevant lines.
     * If not provided, the namespace will be used to filter the stack trace.
     */
    moduleName?: string;
    /**
     * Show complete stack of deprecation triggered.
     *
     * @default false
     */
    showStackTrace?: boolean;
    /**
     * Show warning only if deprecated code is being accessed directly by running project,
     * instead of being accessed by another dependency.
     *
     * @default true
     */
    directDependency?: boolean;
};
type LoggerOptions = {
    /**
     * Custom stack trace to use when logging the warning.
     * If not provided, the stack trace will be captured automatically.
     */
    customStack?: Array<string>;
};
